import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';

function App() {
  const [etapa, setEtapa] = useState('login'); 
  const [modo, setModo] = useState(''); 
  const [codigo, setCodigo] = useState("");
  const [usuario, setUsuario] = useState(null);
  const [mensagem, setMensagem] = useState("Aguardando crachá...");
  const [processando, setProcessando] = useState(false);
  const [relatorio, setRelatorio] = useState([]);
  const inputRef = useRef(null);

  useEffect(() => { inputRef.current?.focus(); }, [etapa, modo]);

  const handleKeyPress = async (e) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      const valorLimpo = codigo.trim(); 

      if (!valorLimpo || processando) { setCodigo(""); return; }
      setProcessando(true);

      try {
        if (etapa === 'login') {
          const res = await axios.post('http://localhost:3001/login', { codBarras: valorLimpo });
          setUsuario(res.data);
          setEtapa('escolha');
          setMensagem(`Olá, ${res.data.nome}! O que deseja fazer?`);
        } else if (etapa === 'acao') {
          const url = modo === 'retirada' ? '/emprestimo/retirada' : '/emprestimo/devolucao';
          const res = await axios.post(`http://localhost:3001${url}`, { 
            usuarioId: usuario.id, 
            ferramentacod: valorLimpo 
          });
          setMensagem(`✅ ${res.data}`);
          setTimeout(() => setMensagem(modo === 'retirada' ? "Bipe a PRÓXIMA FERRAMENTA" : "Bipe o PRÓXIMO RETORNO"), 2500);
        }
      } catch (err) {
        setMensagem(`❌ ${err.response?.data || "Erro na operação"}`);
      } finally {
        setCodigo("");
        setTimeout(() => { setProcessando(false); inputRef.current?.focus(); }, 800);
      }
    }
  };

  const carregarRelatorio = async () => {
    try {
      const res = await axios.get('http://localhost:3001/admin/status-ferramentas');
      setRelatorio(res.data);
    } catch (err) { console.error(err); }
  };

  const toggleManutencao = async (codigoBarras, statusAtual) => {
    try {
      await axios.post('http://localhost:3001/admin/manutencao', { 
        codigoBarras, emManutencao: statusAtual !== 'manutencao' 
      });
      carregarRelatorio();
    } catch (err) { alert("Erro ao alterar status"); }
  };

  return (
    <div style={styles.container}>
      <img src="/logo-tsea.png" style={styles.logo} alt="TSEA" />
      <h1 style={styles.title}>Sistema de Rastreabilidade</h1>
      
      <div style={styles.card}>
        <h2 style={{ color: processando ? '#999' : '#002d62', minHeight: '60px', marginBottom: '20px' }}>{mensagem}</h2>

        {/* INPUT DE SCANNER (Aparece no Login e nas Ações) */}
        {(etapa === 'login' || etapa === 'acao') && (
          <div style={styles.column}>
            <input 
              ref={inputRef} 
              value={codigo} 
              onChange={(e) => setCodigo(e.target.value)} 
              onKeyDown={handleKeyPress} 
              placeholder="Aguardando scanner..." 
              style={{...styles.input, borderColor: etapa === 'acao' ? '#0055ff' : '#ccc'}} 
              autoComplete="off" 
              disabled={processando}
            />
            {etapa === 'acao' && (
              <button onClick={() => { setEtapa('escolha'); setMensagem(`Olá, ${usuario.nome}!`); }} style={styles.btnVoltar}>
                ← Voltar para Opções
              </button>
            )}
          </div>
        )}

        {/* MENU DE ESCOLHA */}
        {etapa === 'escolha' && (
          <div style={styles.column}>
            <button onClick={() => { setModo('retirada'); setEtapa('acao'); setMensagem("Modo RETIRADA: Bipe o item"); }} style={{...styles.button, backgroundColor: '#0055ff'}}>RETIRAR FERRAMENTAS</button>
            <button onClick={() => { setModo('devolucao'); setEtapa('acao'); setMensagem("Modo DEVOLUÇÃO: Bipe o item"); }} style={{...styles.button, backgroundColor: '#28a745'}}>DEVOLVER FERRAMENTAS</button>
            {usuario?.tipo === 'admin' && (
              <button onClick={() => { setEtapa('admin'); carregarRelatorio(); setMensagem("Painel de Controle"); }} style={{...styles.button, backgroundColor: '#6f42c1'}}>📊 PAINEL ADMINISTRADOR</button>
            )}
            <button onClick={() => window.location.reload()} style={styles.btnSair}>ENCERRAR SESSÃO</button>
          </div>
        )}

        {/* TABELA ADMIN */}
        {etapa === 'admin' && (
          <div>
            <table style={styles.table}>
              <thead>
                <tr style={styles.tableHeader}>
                  <th>Ferramenta</th>
                  <th>Status</th>
                  <th>Com quem?</th>
                  <th>Ação</th>
                </tr>
              </thead>
              <tbody>
                {relatorio.map((r, i) => (
                  <tr key={i} style={styles.tr}>
                    <td style={styles.td}>{r.nome}</td>
                    <td style={{ ...styles.td, fontWeight: 'bold', color: r.status === 'disponivel' ? '#28a745' : r.status === 'manutencao' ? '#ffc107' : '#dc3545' }}>
                      {r.status.toUpperCase()}
                    </td>
                    <td style={styles.td}>{r.status === 'em_uso' ? r.usuario_atual : '--'}</td>
                    <td style={styles.td}>
                      <button onClick={() => toggleManutencao(r.codigoBarras, r.status)} style={{...styles.btnMini, backgroundColor: r.status === 'manutencao' ? '#28a745' : '#ffc107'}}>
                        {r.status === 'manutencao' ? 'Ativar' : 'Manutenção'}
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            <button onClick={() => { setEtapa('escolha'); setMensagem(`Olá, ${usuario.nome}!`); }} style={styles.buttonGray}>
              ← Sair do Painel
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

const styles = {
  container: { textAlign: 'center', padding: '40px', backgroundColor: '#f0f2f5', minHeight: '100vh', fontFamily: 'Segoe UI, Arial, sans-serif' },
  logo: { width: '180px', marginBottom: '10px' },
  title: { color: '#002d62', fontWeight: 'bold', marginBottom: '30px' },
  card: { padding: '40px', backgroundColor: 'white', borderRadius: '20px', display: 'inline-block', boxShadow: '0 10px 25px rgba(0,0,0,0.1)', minWidth: '600px' },
  input: { padding: '18px', fontSize: '22px', width: '380px', borderRadius: '12px', border: '3px solid #ccc', textAlign: 'center', outline: 'none', transition: '0.3s' },
  button: { padding: '20px', color: 'white', border: 'none', borderRadius: '10px', margin: '10px', cursor: 'pointer', width: '350px', fontSize: '18px', fontWeight: 'bold', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' },
  column: { display: 'flex', flexDirection: 'column', alignItems: 'center' },
  btnSair: { marginTop: '25px', background: 'none', border: '2px solid #dc3545', color: '#dc3545', padding: '12px 25px', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' },
  btnVoltar: { background: 'none', border: 'none', color: '#0055ff', marginTop: '20px', cursor: 'pointer', fontWeight: 'bold', fontSize: '16px', textDecoration: 'underline' },
  buttonGray: { marginTop: '25px', padding: '12px 30px', backgroundColor: '#6c757d', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' },
  table: { width: '100%', borderCollapse: 'collapse', marginTop: '20px' },
  tableHeader: { borderBottom: '2px solid #002d62', textAlign: 'left', color: '#002d62' },
  tr: { borderBottom: '1px solid #eee' },
  td: { padding: '15px 10px', textAlign: 'left' },
  btnMini: { padding: '8px 12px', border: 'none', borderRadius: '6px', cursor: 'pointer', fontWeight: 'bold', fontSize: '12px' }
};

export default App;
